INSERT INTO `our_products` (`id`, `title`, `slug`, `description`, `image`, `created_at`, `updated_at`) VALUES
(16, 'Solar Power Plant Installations in Kochi', 'solar-power-plant-kerala-kochi', '<h2>Solar Power Plant&nbsp;<br>Installations in Kochi</h2><p>Solar Master offers the customers a choice of two smart versatile techniques in solar power plants.</p><ol><li>On Grid Solar Power Plants</li><li>Off Grid Solar Power Plants</li><li>Hybrid Solar Power Plants</li></ol><p>For residential projects Kerala ANERT / SECI / MNRI subsidy is available with us. For commercial projects, they can claim AD tax benefits corresponding to subsidy. Installing solar power plants can significantly reduce your electricity bills. Solar-powered products are eco-friendly and do not cause any harm to the environment. Solar Master has successfully completed installations across Kerala, especially in Kochi, Ernakulam district.</p>', 'uploads/products/1777370118.jpg', '2026-04-28 04:25:18', '2026-04-29 08:17:29'),
(17, 'EV Charging Stations Installation in Kochi', 'electric-vehicle-charging-stations-installation-kochi', '<h3>EV Charger Installation by SolarMaster</h3><p>As the demand for electric vehicles (EVs) rises across Kerala, reliable, high-performance charging infrastructure is more important than ever. SolarMaster is proud to be a top EV Charging Station installer in Kochi and across Kerala, offering complete solutions for residential, commercial, and investment purposes.<br>With a focus on quality, efficiency, and sustainability, SolarMaster makes EV charging accessible, seamless, and future-ready.</p>', 'uploads/products/1777370289.jpg', '2026-04-28 04:28:09', '2026-04-30 01:34:49'),
(18, 'Lightning Arresters in Kerala', 'lightning-arresters', '<h3>Comprehensive Lightning Protection Systems</h3><p>SolarMaster delivers certified and precision-engineered lightning protection solutions across Kerala. Our systems are designed to protect residential, commercial, and industrial properties, as well as solar installations, from the harmful effects of lightning strikes. With a professional approach and adherence to national safety standards, we ensure optimal safety for your infrastructure.</p>', 'uploads/products/1777370455.jpg', '2026-04-28 04:30:55', '2026-04-30 01:21:43'),
(19, 'Solar Power Plant Cleaning & Technical Services', 'solar-power-plant-technical-and-cleaning-services-kerala', '<h4><strong>Keep Your Solar Panels Performing at Their Best with SolarMaster</strong></h4><p>Have you ever noticed a drop in your solar panel performance and wondered why? Just like any other equipment, <strong>solar panels need regular care</strong>. Dust, bird droppings, tree leaves, and pollution can block sunlight and reduce energy production, costing you money every day.</p><p>At <a href=\"https://www.solarmaster.in/\"><strong>SolarMaster Kochi</strong></a>, we offer <strong>professional cleaning and technical services</strong> for residential, commercial, and industrial <strong>solar power plants across Kerala</strong>, ensuring your system works at peak efficiency all year round.</p>', 'uploads/products/1777370939.webp', '2026-04-28 04:38:59', '2026-04-30 01:08:23'),
(20, 'Solar Water Heater', 'solar-water-heater-kerala-kochi', '<h2>Solar Water Heater</h2><p>We are one of the leading solar water heater suppliers in Kerala. We have installed a large number of solar water heaters both commercial and residential, across Kerala especially in Kochi of Ernakulam district. Subsidized and non subsidized solar water heaters are available with us. We install solar water heaters of the best quality at the lowest prices. We are dealing with V guard, hykon, Soura, supreme, tata, racold etc water heaters.<br>Solar Water heaters are now a mature technology. Wide spread utilisation of solar water heaters can reduce a significant portion of the conventional energy being used for heating water at homes and other commercial establishments.</p>', 'uploads/products/1777371056.jpg', '2026-04-28 04:40:56', '2026-04-30 01:00:23'),
(21, 'Solar Lights Installation in Kerala', 'solar-lights-products-kerala-kochi', '<h2>Solar Lights Installation in Kerala</h2>\r\nSolar Master is one of the leading suppliers of solar energy powered LED lights in Kerala. The solar lights that we supply include  street lights,  wall mounted lights,  garden lights, solar lanterns etc<br>\r\nSo far we have completed various projects, both residential and commercial in Kerala especially in Ernakulam, Kottayam, Thrissur, Idukki, Palakkad .<br>\r\nOur latest technology ensures you a convenient and endurable way to light your home or industrial establishment at a modest price and with low maintenance.', 'uploads/products/1777371310.jpg', '2026-04-28 04:45:10', '2026-04-28 08:08:03'),
(22, 'Solar Panels, Inverters & Batteries', 'solar-panels-inverters-batteries', '<h2>Solar Panels Installation In Kerala</h2><p>Solar panels are the key components in a solar power plant system. Solar Master is one of the leading solar panel distributors in Kochi, the Ernakulam district of Kerala.<br>Solar Master provides you with a huge collection of Solar panels of capacities ranging from 5 W to 380 W. From the start-up of our company, we have so far done 600 KW of supply as well as installation across Kerala, specifically in Ernakulam, Thrissur, Kottayam, and Calicut districts. We supply approved solar panels with all certifications at the lowest price in the industry. Solar Master provides world-class imported products like SunPower, Solar World, Hanwha, Q-Cells, As, Kirloskar, etc.<br>We are mainly dealing with poly-crystalline and monocrystalline panels. We offer a 25-year warranty for our panels. Our services are available all over Kerala, and they include on-site delivery and installation in a minimal span of time.</p>', 'uploads/products/1777371921.jpg', '2026-04-28 04:55:21', '2026-04-29 07:06:12');

