(5, 'When Communities Act, The Earth Heals.', 'when-communities-act-the-earth-heals', 'Promoting sustainable energy solutions and environmental awareness for a cleaner, healthier planet.', 'posts/printing-services-in-kerala-when-communities-act-the-earth-heals.jpg', NULL, 1, 1, 0, '2025-11-08 10:35:51', '2026-03-25 06:47:30', 0, NULL, NULL, NULL, NULL, NULL),
(6, 'Protect the Planet. Empower the Future.', 'protect-the-planet-empower-the-future', 'Join our mission to recycle, reuse, and responsibly manage electronic waste for a sustainable future.', 'posts/printing-services-in-kerala-protect-the-planet-empower-the-future.jpg', NULL, 1, 1, 0, '2025-11-08 10:45:18', '2026-03-25 06:47:30', 0, NULL, NULL, NULL, NULL, NULL),
(12, 'Anirudhan A P', 'anirudhan-m-p', 'Before installing solar On-grid power plant, I had electricity bill about 7000-8000. Now I am paying 45 rupees as bill. Thus a huge amount of money is saved. Team Solar Master was very responsible and efficient at their work.', 'posts/printing-services-in-kerala-anirudhan-m-p.png', NULL, 8, 1, 0, '2025-11-08 15:40:12', '2026-04-11 01:26:29', 0, NULL, NULL, NULL, NULL, NULL),
(13, 'Sasi T K', 'sasi-t-k', 'When I had thought of lightening my garden and yard I chose electrical lighting firstly, but later on hearing about solar lights. I made a comparison between the two. Then I found that solar lightning is the cheapest because it doesn’t need cable, cable conduit, switches, digging the yard and garden, labour and other accessories. Now I have installed the solar lights. They can switch ON/OFF automatically and I can avoid electricity charge towards them. Thanks SOLAR MASTER for their excellent support.', 'posts/printing-services-in-kerala-sasi-t-k.png', NULL, 8, 1, 0, '2025-11-08 15:41:31', '2026-04-11 01:26:10', 0, NULL, NULL, NULL, NULL, NULL),
(14, '15000+', '15000', '<p>Students</p>', NULL, NULL, 4, 1, 0, '2025-11-08 15:44:47', '2026-05-11 07:32:08', 0, NULL, NULL, NULL, NULL, NULL),
(15, '25+', '25', '<p>Courses</p>', NULL, NULL, 4, 1, 0, '2025-11-08 15:46:52', '2026-05-11 07:32:46', 0, NULL, NULL, NULL, NULL, NULL),
(16, '98%', '98', '<p>Success rate</p>', NULL, NULL, 4, 1, 0, '2025-11-08 15:47:39', '2026-05-11 07:33:56', 0, NULL, NULL, NULL, NULL, NULL),
(17, 'Real Impact', 'real-impact', '<p>Advanced technologies tailored to meet modern environmental challenges.</p>', 'posts/printing-services-in-kerala-real-impact.png', NULL, 5, 1, 0, '2025-11-09 01:44:57', '2026-03-25 06:47:30', 0, NULL, NULL, NULL, NULL, NULL),
(18, 'Real People', 'real-people', '<p>A team of educators, innovators, and volunteers committed to building a greener tomorrow.</p>', 'posts/printing-services-in-kerala-real-people.png', NULL, 5, 1, 0, '2025-11-09 01:45:45', '2026-03-25 06:47:30', 0, NULL, NULL, NULL, NULL, NULL),
(19, 'Real Change', 'real-change', '<p>Every programme is designed for long-term environmental benefit, not short-lived activity.</p>', 'posts/printing-services-in-kerala-real-change.png', NULL, 5, 1, 0, '2025-11-09 01:46:19', '2026-03-25 06:47:30', 0, NULL, NULL, NULL, NULL, NULL),
(26, 'Cancellation & Refunds', 'cancellation-refunds', '<div class=\"policy-section\">\r\n<div class=\"auto-container\">\r\n<div class=\"row clearfix\">\r\n<div class=\"col-lg-12 col-md-12 col-sm-12\">\r\n<div class=\"policy-content\">\r\n<h2>Cancellation &amp; Refunds Policy</h2>\r\n<p>At ENVED Foundation, we value your support and trust in our mission to create a sustainable future. This policy outlines our procedures regarding donation cancellations and refunds.</p>\r\n<h3>Donation Cancellations</h3>\r\n<p>If you wish to cancel a recurring donation, you may do so by:</p>\r\n<ul>\r\n<li>Contacting us at <a href=\"mailto:support@envedfoundation.org\">ngo@envedfoundation.org</a></li>\r\n<li>Calling our support team at +91 9846066620&nbsp;</li>\r\n<li>Using the cancellation option in your donor portal (if available)</li>\r\n</ul>\r\n<p>Please note that cancellation requests should be submitted at least 3 business days before your next scheduled donation to ensure processing.</p>\r\n<h3>Refund Policy</h3>\r\n<p>ENVED Foundation treats all donations as final. However, we understand that exceptional circumstances may occur. Refund requests will be considered under the following conditions:</p>\r\n<ul>\r\n<li>Unauthorized transaction made from your account</li>\r\n<li>Technical error resulting in duplicate charges</li>\r\n<li>Donation made by mistake (must be reported within 7 days)</li>\r\n</ul>\r\n<h3>Processing Refunds</h3>\r\n<p>Approved refunds will be processed within 7-10 business days and credited to the original payment method. Please allow additional time for the refund to reflect in your account based on your financial institution\'s policies.</p>\r\n<h3>Event Registration Cancellations</h3>\r\n<p>For paid events:</p>\r\n<ul>\r\n<li>Cancellations made 14+ days before the event: Full refund</li>\r\n<li>Cancellations made 7-13 days before the event: 50% refund</li>\r\n<li>Cancellations made less than 7 days before the event: No refund, but donation receipt provided</li>\r\n</ul>\r\n<h3>Contact Information</h3>\r\n<p>For any questions regarding our cancellation and refund policy, please contact us:</p>\r\n<div class=\"contact-info-box\">\r\n<p><strong>Email:</strong> <a href=\"mailto:support@envedfoundation.org\">ngo@envedfoundation.org</a></p>\r\n<p><strong>Phone:</strong> +91 9846066620&nbsp;</p>\r\n<p><strong>Hours:</strong> Monday-Friday, 9:00 AM - 6:00 PM IST</p>\r\n</div>\r\n<div class=\"back-to-home text-center mt-5\"><a class=\"theme-btn btn-style-one\" href=\"../../\"> <span class=\"btn-title\">Back to Home</span> </a></div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>', NULL, NULL, 17, 1, 1, '2025-11-15 15:47:20', '2025-11-25 01:14:55', NULL, NULL, NULL, NULL, NULL, NULL),
(27, 'Terms and conditions', 'terms-and-conditions', '<div class=\"policy-section\">\r\n<div class=\"auto-container\">\r\n<div class=\"row clearfix\">\r\n<div class=\"col-lg-12 col-md-12 col-sm-12\">\r\n<div class=\"policy-content\">\r\n<h2>Terms and Conditions</h2>\r\n<p>Welcome to ENVED Foundation. By accessing our website and using our services, you agree to comply with and be bound by the following terms and conditions.</p>\r\n<h3>Acceptance of Terms</h3>\r\n<p>By accessing and using the ENVED Foundation website (envedfoundation.org), you accept and agree to be bound by the terms and provision of this agreement.</p>\r\n<h3>Use of Website</h3>\r\n<p>You agree to use our website for lawful purposes only. You may not:</p>\r\n<ul>\r\n<li>Use our website in any way that breaches any applicable local, national, or international law</li>\r\n<li>Copy, reproduce, or redistribute content without permission</li>\r\n<li>Transmit any data that contains viruses or other harmful components</li>\r\n<li>Attempt to gain unauthorized access to our systems</li>\r\n</ul>\r\n<h3>Donations</h3>\r\n<p>All donations made to ENVED Foundation are voluntary and non-refundable, except in exceptional circumstances as outlined in our Refund Policy.</p>\r\n<h3>Intellectual Property</h3>\r\n<p>All content on this website, including text, graphics, logos, and images, is the property of ENVED Foundation and is protected by copyright and intellectual property laws.</p>\r\n<h3>Third-Party Links</h3>\r\n<p>Our website may contain links to third-party websites. These links are provided for your convenience only. ENVED Foundation has no control over and assumes no responsibility for the content, privacy policies, or practices of any third-party sites.</p>\r\n<h3>Limitation of Liability</h3>\r\n<p>ENVED Foundation will not be liable for any indirect, special, or consequential loss or damage arising under these terms and conditions or in connection with our website.</p>\r\n<h3>Changes to Terms</h3>\r\n<p>We reserve the right to modify these terms at any time. Changes will be effective immediately upon posting to the website. Your continued use of the website constitutes acceptance of the modified terms.</p>\r\n<h3>Governing Law</h3>\r\n<p>These terms and conditions are governed by and construed in accordance with the laws of India. Any disputes relating to these terms will be subject to the exclusive jurisdiction of the courts of India.</p>\r\n<h3>Contact Information</h3>\r\n<p>For any questions regarding our terms and conditions, please contact us:</p>\r\n<div class=\"contact-info-box\">\r\n<p><strong>Email:</strong> <a href=\"mailto:legal@envedfoundation.org\">ngo@envedfoundation.org</a></p>\r\n<p><strong>Phone:</strong> +91 9846066620&nbsp;</p>\r\n<p><strong>Hours:</strong> Monday-Friday, 9:00 AM - 6:00 PM IST</p>\r\n</div>\r\n<div class=\"back-to-home text-center mt-5\"><a class=\"theme-btn btn-style-one\" href=\"../../\"> <span class=\"btn-title\">Back to Home</span> </a></div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>', NULL, NULL, 18, 1, 0, '2025-11-15 16:35:12', '2025-11-25 01:15:45', NULL, NULL, NULL, NULL, NULL, NULL),
(28, 'Shipping Policy', 'shipping-policy', '<div class=\"policy-section\">\r\n<div class=\"auto-container\">\r\n<div class=\"row clearfix\">\r\n<div class=\"col-lg-12 col-md-12 col-sm-12\">\r\n<div class=\"policy-content\">\r\n<h2>Shipping Policy</h2>\r\n<p>ENVED Foundation primarily deals with environmental initiatives, awareness programs, and digital resources. However, for certain campaigns and donor appreciation, we may ship physical items.</p>\r\n<h3>Digital Products/Services</h3>\r\n<p>Most of our resources, including educational materials, certificates, and receipts, are delivered digitally via email immediately or within 24 hours of completion/contribution.</p>\r\n<h3>Physical Items</h3>\r\n<p>For campaigns that involve physical items (such as merchandise, trees for planting, or event materials):</p>\r\n<ul>\r\n<li>Processing time: 3-5 business days</li>\r\n<li>Shipping time: 7-14 business days within India</li>\r\n<li>International shipping: 15-30 business days (where applicable)</li>\r\n</ul>\r\n<h3>Shipping Methods</h3>\r\n<p>We use reliable shipping partners including India Post, DTDC, and other courier services depending on the destination and item size.</p>\r\n<h3>Shipping Costs</h3>\r\n<p>Shipping costs are typically covered by ENVED Foundation for donor appreciation items. For specific campaigns requiring shipping fees, this will be clearly stated during the donation/registration process.</p>\r\n<h3>Tracking</h3>\r\n<p>For shipped items, tracking information will be provided via email when available.</p>\r\n<h3>Undeliverable Packages</h3>\r\n<p>If a package is returned to us as undeliverable, we will attempt to contact you using the information provided. If we cannot reach you after three attempts, the item may be considered abandoned.</p>\r\n<h3>Damaged Items</h3>\r\n<p>If your item arrives damaged, please contact us within 7 days of receipt with photos of the damaged package and item. We will arrange for a replacement where possible.</p>\r\n<h3>Contact</h3>\r\n<p>For shipping-related inquiries, please contact:</p>\r\n<div class=\"contact-info-box\">\r\n<p><strong>Email:</strong> <a href=\"mailto:shipping@envedfoundation.org\">ngo@envedfoundation.org</a></p>\r\n<p><strong>Phone:</strong> +91 9846066620&nbsp;</p>\r\n<p><strong>Hours:</strong> Monday-Friday, 9:00 AM - 6:00 PM IST</p>\r\n</div>\r\n<div class=\"back-to-home text-center mt-5\"><a class=\"theme-btn btn-style-one\" href=\"../../\"> <span class=\"btn-title\">Back to Home</span> </a></div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>', NULL, NULL, 19, 1, 0, '2025-11-15 16:37:48', '2025-11-25 01:16:18', NULL, NULL, NULL, NULL, NULL, NULL),
(29, 'Privacy Policy', 'privacy-policy', '<h2>Privacy Policy</h2><p>At Solar Master, we are committed to protecting your privacy and ensuring the security of your personal information. This Privacy Policy explains how we collect, use, and safeguard the information you provide when using our website and services.</p><h2>Information We Collect</h2><p>We may collect the following types of information:</p><ul><li>Personal identification information such as name, email address, phone number, and location</li><li>Enquiry and service request details</li><li>Project-related information shared by customers</li><li>Payment and billing information (if applicable)</li><li>Website usage data through cookies and analytics tools</li></ul><h2>How We Use Your Information</h2><p>We use the information we collect to:</p><ul><li>Respond to enquiries and provide customer support</li><li>Process service requests and project consultations</li><li>Improve our products, services, and website experience</li><li>Send important updates, offers, or service-related communications</li><li>Maintain internal records and comply with legal obligations</li></ul><h2>Data Security</h2><p>Solar Master implements appropriate technical and organizational security measures to protect your personal information against unauthorized access, misuse, alteration, or disclosure. Sensitive information is protected using secure technologies and industry-standard security practices.</p><h2>Data Sharing</h2><p>We do not sell, rent, or trade your personal information to third parties. We may share information only with:</p><ul><li>Trusted service providers assisting in business operations</li><li>Technical or hosting partners under confidentiality agreements</li><li>Government or legal authorities when required by law</li></ul><h2>Cookies</h2><p>Our website may use cookies and similar technologies to enhance user experience and analyze website traffic. You can disable cookies through your browser settings; however, some features of the website may not function properly.</p><h2>Your Rights</h2><p>You have the right to:</p><ul><li>Access the personal information we hold about you</li><li>Request correction of inaccurate or incomplete information</li><li>Request deletion of your personal data</li><li>Opt out of promotional or marketing communications</li></ul><h2>Third-Party Links</h2><p>Our website may contain links to external websites. Solar Master is not responsible for the privacy practices or content of third-party websites. We encourage users to review the privacy policies of those websites separately.</p><h2>Changes to This Privacy Policy</h2><p>Solar Master may update this Privacy Policy from time to time. Any updates will be posted on this page with immediate effect.</p><h2>Contact Us</h2><p>If you have any questions regarding this Privacy Policy or how your information is handled, please contact us:</p><p><strong>Solar Master</strong><br>Email: support@solarmaster.in<br>Phone: +91 8129966688&nbsp;</p>', NULL, NULL, 20, 1, 1, '2025-11-15 16:39:13', '2026-05-06 01:56:09', NULL, NULL, NULL, NULL, NULL, NULL),
