(130, 'Does Hub support both Elementor and WP Bakery Page Builder?', 'does-hub-support-both-elementor-and-wp-bakery-page-builder', 'Yes, Wexy supports Elementor and WPBakery, but you should choose one builder and stick with it.', NULL, NULL, 9, 1, 0, '2026-03-12 07:50:07', '2026-03-12 07:50:07', NULL, NULL, NULL, NULL, NULL, NULL),
