(162, 'Hot & cool lamination machine', 'hot-cool-lamination-machine', 'A hot & cool (cold) lamination machine is a versatile finishing machine used to protect and enhance printed materials by applying a thin plastic film using heat (hot lamination) or pressure (cold lamination).\r\n\r\nIt is widely used in printing shops, advertising industries, and offices for improving the durability, appearance, and lifespan of prints.', 'posts/printing-services-in-kerala-hot-cool-lamination-machine.jpg', NULL, 6, 1, 0, '2026-03-17 23:56:03', '2026-03-25 06:47:32', 0, NULL, NULL, NULL, NULL, NULL),
(172, '2', '2', 'Total projects', 'posts/printing-services-in-kerala-2.jpg', NULL, 49, 1, 0, '2026-03-19 01:21:33', '2026-03-25 06:47:32', NULL, NULL, NULL, NULL, NULL, NULL),
(173, 'HP Latex 335 Printers', 'hp-latex-335-printers', 'The HP Latex 335 Printer is a professional large-format printing machine designed mainly for signage, banners, posters, and vehicle graphics. It uses advanced HP Latex printing technology, which is known for producing high-quality, durable, and eco-friendly prints.', 'posts/printing-services-in-kerala-hp-latex-335-printers.png', NULL, 6, 1, 0, '2026-03-20 04:22:11', '2026-03-25 06:47:32', NULL, NULL, NULL, NULL, NULL, NULL),
(174, 'High quality eco-solvent printer', 'high-quality-eco-solvent-printer', 'A high-quality eco-solvent printer is a large-format digital printing machine that uses eco-solvent inks to produce sharp, vibrant, and durable prints for both indoor and outdoor applications.\r\n\r\nEco-solvent inks are mild, low-odor, and environmentally safer compared to traditional solvent inks, making them suitable for indoor environments while still offering strong outdoor durability', 'posts/printing-services-in-kerala-high-quality-eco-solvent-printer.jpg', NULL, 6, 1, 0, '2026-03-20 04:24:27', '2026-03-25 06:47:32', NULL, NULL, NULL, NULL, NULL, NULL),
(175, 'Vinyl Plotter cutting machine', 'vinyl-plotter-cutting-machine', 'A vinyl plotter cutting machine (also called a vinyl cutter or cutting plotter) is a computer-controlled machine used to cut designs, letters, and graphics from materials like vinyl, sticker sheets, and heat transfer film.\r\n\r\nInstead of printing, it uses a sharp blade to cut shapes based on digital designs created in software. These designs are sent from a computer to the machine, which then precisely cuts the material.', 'posts/printing-services-in-kerala-vinyl-plotter-cutting-machine.jpg', NULL, 6, 1, 0, '2026-03-20 04:35:08', '2026-03-25 06:47:32', NULL, NULL, NULL, NULL, NULL, NULL),
(176, 'Automatic Lamination Machine', 'automatic-lamination-machine', 'An automatic lamination machine is an advanced printing finishing machine that automatically applies a protective plastic film over printed materials using heat, pressure, or adhesive, without manual intervention.\r\n\r\nIt is designed for high-speed, large-volume production, commonly used in printing presses, packaging industries, and advertising businesses.\r\n\r\nUnlike manual machines, automatic laminators handle feeding, laminating, cutting, and stacking processes automatically, increasing efficiency and reducing labor.', 'posts/printing-services-in-kerala-automatic-lamination-machine.jpg', NULL, 6, 1, 0, '2026-03-20 04:37:24', '2026-03-25 06:47:32', NULL, NULL, NULL, NULL, NULL, NULL),
(177, 'Co2 Laser Cutting Machine', 'co2-laser-cutting-machine-2', 'A CO₂ laser cutting machine is a high-precision digital machine that uses a carbon dioxide (CO₂) laser beam to cut, engrave, or mark materials with extreme accuracy.\r\n\r\nIt works by generating a focused infrared laser beam using CO₂ gas and directing it onto the material surface to melt, burn, or vaporize the material, resulting in clean and smooth cuts.\r\n\r\nThese machines are widely used in advertising, woodworking, textile, packaging, and craft industries.', 'posts/printing-services-in-kerala-co2-laser-cutting-machine.jpg', NULL, 6, 1, 0, '2026-03-20 04:43:25', '2026-03-25 06:47:32', NULL, NULL, NULL, NULL, NULL, NULL),
(178, 'CNC Router Cutting Machine', 'cnc-router-cutting-machine', 'A CNC router cutting machine is a computer-controlled cutting and engraving machine used to shape, cut, and carve materials like wood, acrylic, plastic, and soft metals with high precision.\r\n\r\n“CNC” stands for Computer Numerical Control, meaning the machine operates using pre-programmed design files (G-code) instead of manual work. It automatically moves along X, Y, and Z axes to perform accurate cutting and carving.', 'posts/printing-services-in-kerala-cnc-router-cutting-machine.jpg', NULL, 6, 1, 0, '2026-03-20 04:46:18', '2026-03-25 06:47:32', NULL, NULL, NULL, NULL, NULL, NULL),
(179, 'Channel letter bending Machine', 'channel-letter-bending-machine', 'A channel letter bending machine is a specialized CNC machine used to bend metal strips (mainly aluminum or stainless steel) into shapes to create 3D illuminated sign letters (channel letters).\r\n\r\nIt is widely used in the advertising and signage industry to produce LED sign boards, shop name boards, and branding letters.\r\n\r\nThe machine works by automatically performing feeding, notching (cutting slots), and bending based on a digital design file, allowing precise and fast production of letter shapes.', 'posts/printing-services-in-kerala-channel-letter-bending-machine.jpg', NULL, 6, 1, 0, '2026-03-20 04:49:23', '2026-03-25 06:47:32', NULL, NULL, NULL, NULL, NULL, NULL),
(180, 'Liquid acrylic making machine', 'liquid-acrylic-making-machine', 'A liquid acrylic making machine is an industrial or semi-industrial system used to produce, mix, or cure liquid acrylic materials for applications like LED signage, coatings, paints, and decorative products.\r\n\r\nIn signage industries, it is commonly called a liquid acrylic curing machine, where liquid acrylic is poured into molds (like channel letters) and then hardened using controlled heat or chemical curing to form solid, glossy surfaces.\r\n\r\nIn manufacturing, it can also refer to acrylic emulsion or resin production machines, where liquid acrylic is created by chemical mixing and polymerization processes.', 'posts/printing-services-in-kerala-liquid-acrylic-making-machine.jpg', NULL, 6, 1, 0, '2026-03-20 04:51:49', '2026-03-25 06:47:32', NULL, NULL, NULL, NULL, NULL, NULL),
