  PRIMARY KEY (`id`),
  KEY `fk_product_faqs_product` (`product_id`)
) ENGINE=InnoDB AUTO_INCREMENT=2506 DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_unicode_ci;

