INSERT INTO `product_faqs` (`id`, `product_id`, `question`, `answer`, `created_at`, `updated_at`) VALUES
(2481, 17, 'Can I install an EV charger at my home in Kerala?', 'Yes, if you have proper electrical capacity and a parking space. Our team will guide you through the process.', '2026-04-30 06:21:51', '2026-04-30 06:21:51'),
(2482, 17, 'What’s the cost of an EV charger installation in Kochi?', 'It depends on charger type, features, and site conditions. We provide transparent quotes.', '2026-04-30 06:21:51', '2026-04-30 06:21:51'),
(2483, 17, 'Can EV chargers run on solar power?', 'Yes. We offer integrated solar + EV charging systems for energy savings and sustainability.', '2026-04-30 06:21:51', '2026-04-30 06:21:51'),
(2484, 17, 'How long does the installation take?', 'Usually between 1 to 3 working days, depending on site readiness.', '2026-04-30 06:21:51', '2026-04-30 06:21:51'),
(2485, 17, 'Are government subsidies available?', 'Yes, subject to eligibility. We help with the application and documentation.', '2026-04-30 06:21:51', '2026-04-30 06:21:51'),
(2491, 16, 'What is the cost of solar panel installation with Solar Master in Kerala?', 'The cost of solar panel installation with Solar Master in Kerala typically ranges from ₹1 lakh for residential systems, depending on system size and energy requirements. Larger commercial projects may cost more but come with greater long-term savings.', '2026-04-30 07:02:23', '2026-04-30 07:02:23'),
(2492, 16, 'Can I run 2 AC units on a 5kW solar system from Solar Master?', 'Yes, up to 3 air conditioners can be powered, depending on the capacity of the air conditioners. However, Solar Master recommends a detailed energy audit to ensure your solar system matches your household’s electricity demand.', '2026-04-30 07:02:23', '2026-04-30 07:02:23'),
(2493, 16, 'How much does a 1000 square foot house solar system cost in Kochi or Thrissur?', 'For a 1000 sq. ft. home, Solar Master usually installs a 3kW to 5kW solar system, costing between ₹1.25 lakh and ₹3 lakh after subsidies. The exact cost depends on roof space, sunlight availability, and power usage.', '2026-04-30 07:02:23', '2026-04-30 07:02:23'),
(2494, 16, 'How does Solar Master install solar panels in Kerala?', 'Solar Master follows a step-by-step process: site survey, custom system design, government approvals, rooftop mounting, inverter setup, and final grid connection. The installation usually takes 2–4 days after approvals.', '2026-04-30 07:02:23', '2026-04-30 07:02:23'),
(2495, 16, 'How long do Solar Master solar panels last in Indian conditions?', 'Solar Master uses panels with a 30-year performance warranty. Even in Kerala’s coastal climate, panels retain 80–90% efficiency after 30 years when maintained properly.', '2026-04-30 07:02:23', '2026-04-30 07:02:23'),
(2496, 16, 'What maintenance is required for Solar Master solar systems in Kerala?', 'Solar systems require minimal upkeep—mostly cleaning panels every 2–3 months to remove dust, bird droppings, and leaves. Solar Master also offers annual maintenance contracts (AMC) for peace of mind.', '2026-04-30 07:02:23', '2026-04-30 07:02:23'),
(2497, 16, 'Does Solar Master provide financing options in India?', 'Yes, Solar Master partners with banks and NBFCs in Kerala to offer EMI-based solar loans, making it easy for homeowners and businesses to switch to solar with low upfront costs.', '2026-04-30 07:02:23', '2026-04-30 07:02:23'),
(2498, 16, 'How much money can I save with Solar Master solar panels in Kerala?', 'On average, Kerala households save ₹1,500 to ₹3,000 per month on electricity bills with solar. Over 20–25 years, savings can reach ₹5–10 lakhs, depending on system size and consumption.', '2026-04-30 07:02:23', '2026-04-30 07:02:23'),
(2499, 16, 'Does Solar Master provide solar battery storage in Thrissur and Kasargod?', 'Yes! Solar Master installs lithium-ion solar batteries to store excess energy. This ensures uninterrupted power during Kerala’s frequent outages and maximizes solar usage.', '2026-04-30 07:02:23', '2026-04-30 07:02:23'),
(2500, 16, 'Can Solar Master install solar panels on flat and tiled roofs?', 'Absolutely. Solar Master uses specialized mounting structures for both flat concrete rooftops and traditional tiled Kerala houses, ensuring maximum durability and energy generation.', '2026-04-30 07:02:23', '2026-04-30 07:02:23'),
(2501, 18, 'Do I need a lightning arrester if I use solar power?', 'Yes. Solar panels are rooftop-mounted and more exposed to lightning. An arrester protects your solar equipment from surge damage.', '2026-05-01 02:04:08', '2026-05-01 02:04:08'),
(2502, 18, 'What is the difference between a conventional and an ESE system?', 'Conventional arresters safely divert lightning without attracting it. ESE systems are banned and not compliant with Indian standards.', '2026-05-01 02:04:08', '2026-05-01 02:04:08'),
(2503, 18, 'How long does installation take?', 'Most installations are completed within 1–2 working days, depending on project complexity.', '2026-05-01 02:04:08', '2026-05-01 02:04:08'),
(2504, 18, 'Are your products certified?', 'Yes. We use only certified and tested lightning protection components.', '2026-05-01 02:04:08', '2026-05-01 02:04:08'),
(2505, 18, 'How often should I get my system inspected?', 'Annually, ideally before the monsoon season.', '2026-05-01 02:04:08', '2026-05-01 02:04:08');

