INSERT INTO `projects` (`id`, `name`, `slug`, `description`, `image`, `skills`, `experience`, `project_category_id`, `created_at`, `updated_at`) VALUES
(4, 'Innovative Wall Visuals by Zoom Innovation', 'innovative-wall-visuals-by-zoom-innovation', 'Wall graphics are custom-designed visual prints applied to walls to enhance interiors and branding. At Zoom Innovation, we create high-quality, durable, and visually striking wall graphics that transform spaces into engaging and professional environments.', 'uploads/projects/printing-services-in-kerala-innovative-wall-visuals-by-zoom-innovati.webp', NULL, NULL, 12, '2026-03-20 07:10:14', '2026-03-26 00:59:26'),
(5, 'Glass Branding Solutions', 'glass-branding-solutions', 'Frosted films are a stylish and functional solution for enhancing privacy while maintaining a modern aesthetic. At Zoom Innovation, we design and install high-quality frosted glass films that transform ordinary glass surfaces into elegant, professional spaces.', 'uploads/projects/printing-services-in-kerala-glass-branding-solutions.webp', NULL, NULL, 11, '2026-03-20 07:13:20', '2026-03-26 00:59:26'),
(6, 'Premium Signage Installation', 'premium-signage-installation', 'Signages play a crucial role in creating a strong first impression and brand identity. At Zoom Innovation, we design and deliver high-quality signage solutions that are visually striking, durable, and tailored to your business needs.', 'uploads/projects/printing-services-in-kerala-premium-signage-installation.webp', NULL, NULL, 10, '2026-03-20 07:15:15', '2026-03-26 00:59:26'),
(7, 'Sun Control Film Installation', 'sun-control-film-installation', 'Sun control films are designed to reduce heat, glare, and harmful UV rays, creating a more comfortable and energy-efficient indoor environment. At Zoom Innovation, we provide high-quality sun control film solutions that enhance both comfort and performance of glass surfaces.', 'uploads/projects/printing-services-in-kerala-sun-control-film-installation.webp', NULL, NULL, 9, '2026-03-20 07:18:19', '2026-03-26 00:59:26'),
(8, 'Premium Canvas Printing', 'premium-canvas-printing', 'Printed canvas is a creative way to showcase images, artwork, and designs with a rich, textured, and artistic finish. At Zoom Innovation, we produce high-quality canvas prints using advanced printing technology to ensure sharp details, vibrant colors, and long-lasting quality.', 'uploads/projects/printing-services-in-kerala-premium-canvas-printing.webp', NULL, NULL, 8, '2026-03-20 07:21:14', '2026-03-26 00:59:26'),
(9, 'Mounted canvas', 'mounted-canvas', 'zgvcsdghbyafun vfagtsyhfuijko,', 'uploads/projects/printing-services-in-kerala-dafhusewfjik.webp', '\"cftgyhujik\"', 'rftgyhujik', 8, '2026-03-21 06:14:10', '2026-03-26 01:37:46');

