INSERT INTO `services` (`id`, `title`, `slug`, `description`, `text1`, `text2`, `text3`, `image`, `created_at`, `updated_at`) VALUES
(12, 'Wall Graphics', 'wall-graphics', 'Create beautiful aesthetics inside and out with interior and exterior graphics and signage that tell brand stories in a more impactful way. With 3M graphic films and over laminates you can make nearly any surface a canvas – whether smooth and flat walls or rough and textured brick walls.\r\n\r\nTransform blank buildings and walls into works of art and extend brands into experiential spaces with 3M graphic films and over laminates. Create stunning, picture-perfect wall graphics and building wraps for almost any surface including textured walls and smooth surfaces, inside and out.\r\n\r\nVinyl Graphics is also known as wall decal, wall sticker, wall tattoo, or wall vinyl, is a vinyl sticker that is affixed to a wall or other smooth surface for decoration and informational purposes.', NULL, NULL, NULL, 'printing-services-kerala-wall-graphics.jpg', '2026-03-12 07:32:06', '2026-03-26 00:33:44'),
(13, 'Frosted/Dusted/Fasara/Clear Graphics', 'frosteddustedfasaraclear-graphics', 'Give your tenants custom and elegant interiors that provide enhanced privacy without sacrificing natural light. 3M™ Glass Finishes let you define spaces without confining them.\r\n\r\nWindows and glass provide perfect surfaces for businesses to expand their brand, enhance privacy and personalize their space. 3M vinyl and non-vinyl window graphics offer a wide range of solutions that support their needs.\r\n\r\nCustomise your space to suit any taste. You can design a space that’s private without making it feel closed off with 3M™ Glass Finishes. Frosted, dusted, textured — you name it, we have the finish to match your style. Create the privacy you need with a design that’s all your own.', NULL, NULL, NULL, 'printing-services-kerala-frosteddustedfasaraclear-graphics.jpg', '2026-03-14 04:52:07', '2026-03-26 00:33:44'),
(14, 'Sun Control & Safety Film', 'sun-control-safety-film', 'When tenants complain about rooms that are too hot or you notice that your energy costs are trending skyward, 3Mâ„¢ Window Films can help increase tenant comfort, conserve energy and even increase safety and security.\r\n\r\nWindow films are a type of window treatment applied to windows and glass surfaces, designed to reduce the amount of solar heat transmitted through the glass. Unlike curtains or blinds that need to be closed to be effective, window films are designed to allow light in, help increase solar reflectivity, reduce heat and glare, and maintain your view, all at the same time. They also increase safety and security; our films offer enhanced protection from accidents, break and entry, and flying glass fragments.', NULL, NULL, NULL, 'printing-services-kerala-sun-control-safety-film.jpg', '2026-03-14 04:53:14', '2026-03-26 00:33:45'),
(18, 'Fire Safety Signages', 'fire-safety-signages', 'We are engaged in manufacturing, wholesaling and trading high quality range of Fire Safety Signages. All the signs are manufactured using quality material and modern technology in strict compliance with industry laid guidelines.\r\n\r\nSafety signs are a type of sign designed to warn of hazards, indicate mandatory actions or required use of Personal protective equipment, prohibit actions or objects, identify the location of firefighting or safety equipment, or marking of exit routes.', NULL, NULL, NULL, 'printing-services-kerala-fire-safety-signages.jpg', '2026-03-16 12:13:58', '2026-03-26 00:33:45'),
(15, 'LED Signages', 'led-signages', 'LED Signage consists of a wide range of indoor and outdoor signage that provides eye-catching experiences with industry leading technology\r\n\r\nZOOM INNOVATION provides all kind of variety in signages with quality and service In today’s world, Led sign boards are one of the best cost-effective solutions for any business and its business promotions.', NULL, NULL, NULL, 'printing-services-kerala-led-signages.jpg', '2026-03-14 06:07:53', '2026-03-26 00:33:45'),
(19, 'Wayfinding Signages', 'wayfinding-signages', 'Wayfinding signage is any type of sign that can help your employees, visitors and customers navigate through even the most confusing environments with a sense of confidence, safety, and security.', NULL, NULL, NULL, 'printing-services-kerala-wayfinding-signages.jpg', '2026-03-20 03:44:19', '2026-03-26 00:33:45'),
(20, 'Printed & Mounted Canvas', 'printed-mounted-canvas', 'A canvas print is the result of an image printed onto canvas which is stretched onto a frame. Canvas prints are used as the final output in an art piece, or as a way to reproduce other forms of art.', NULL, NULL, NULL, 'printing-services-kerala-printed-mounted-canvas.jpg', '2026-03-20 03:47:19', '2026-03-26 00:33:45'),
(21, '3M  Anti-Skid Tape', '3m-anti-skid-tape', 'The 3M™ Safety Walk™ Universal Anti-Slip Coating (Type 1) Series 600 is made of a mineral-coated material attached to a plastic film with a durable resin on the back of which there is a pressure-sensitive adhesive. The anti-slip coating provides an effective, non-slip surface for areas that are little to heavy with shoes. Mainly intended for dry, wet or oily floors in industry and trades with high pedestrian or light vehicle traffic, such as: corridors, production and storage rooms, ramps, stairs, ladders, footboards on machinery and emergency exits. Available in a variety of colors and sizes. Product Color: Black, Safety Yellow, Transparent, White, Yellow', NULL, NULL, NULL, 'printing-services-kerala-3m-anti-skid-tape.jpg', '2026-03-20 03:50:19', '2026-03-26 00:33:45'),
(22, '3M Entryway Matting System', '3m-entryway-matting-system', '3M™ Nomad™ Matting traps, holds, and hides dirt and water. Preventing dirt and water from entering a facility helps to maintain a clean and safe environment, not only by providing a clean appearance, but also by helping to reduce slip and fall incidents. Reducing the amount of water and dirt tracked into a facility can also help prevent damage to floor finishes and reduce the amount of time needed to clean the floors. By decreasing the frequency at which floors need to be stripped, re-coated, and cleaned, you can also help reduce the amount of time, energy, and chemicals needed to carry out these operations.', NULL, NULL, NULL, 'printing-services-kerala-3m-entryway-matting-system.jpg', '2026-03-20 03:54:09', '2026-03-26 00:33:45'),
(23, 'Internal Signages', 'internal-signages', 'Internal signage is crucial to creating a great first impression for your visitors and customers alike. It must be functional, welcoming and informative. Presenting information, activities and events on various signs: Here we provide a wide range of solutions for all your internal signage requirements.', NULL, NULL, NULL, 'printing-services-kerala-internal-signages.jpg', '2026-03-20 03:58:10', '2026-03-26 00:33:45');

